+    unsafe {
+        assert_eq!(
+            initstate_r(123, statebuf.cast(), 32, buf.cast()),
+            libc::EINVAL
+        );
+        frankenlibc_abi::malloc_abi::free(buf.cast());
+        frankenlibc_abi::malloc_abi::free(statebuf.cast());
+    }
+}
